const items = $input.all().map(i => i.json);

const total = items.length;
const autoValides = items.filter(i => i.status === 'traite' || i.decision === 'auto_valider').length;
const attente = items.filter(i => i.status === 'attente').length;
const escalades = items.filter(i => i.status === 'escalade').length;
const reclamations = items.filter(i => i.status === 'reclamation').length;
const tauxAuto = total > 0 ? ((autoValides / total) * 100).toFixed(1) : 0;

const motifs = {};
for (const d of items) {
  const m = d.motif_declare || 'Inconnu';
  motifs[m] = (motifs[m] || 0) + 1;
}

const anomalies = items.filter(d => {
  try { return JSON.parse(d.anomalies || '[]').length > 0; } catch { return false; }
});

const scoreMoyen = total > 0 ? (items.reduce((s, d) => s + (d.score_confiance || 0), 0) / total).toFixed(0) : 0;

return [{ json: {
  total, autoValides, attente, escalades, reclamations, tauxAuto,
  motifs, nbAnomalies: anomalies.length, scoreMoyen,
  dateDebut: new Date(Date.now() - 7*24*60*60*1000).toISOString().split('T')[0],
  dateFin: new Date().toISOString().split('T')[0]
}}];

